export function filterTxForms(ministrySlug: string, query: string): TxItem[] {
  let r = TX_WITH_FORMS
  if (ministrySlug && ministrySlug !== 'all') r = r.filter(t => t.ministrySlug === ministrySlug)
  if (query.trim()) { const q = query.trim(); r = r.filter(t => t.title.includes(q) || t.ministry.includes(q)) }
  return r
}